type Candidate = { cell: Cell; liveNeighbors: number };

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const liveCells = new Set(cells.map(cellKey));
  const candidates = new Map<string, Candidate>();

  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = cellKey(neighbor);
      const existing = candidates.get(k) ?? { cell: neighbor, liveNeighbors: 0 };
      candidates.set(k, { ...existing, liveNeighbors: existing.liveNeighbors + 1 });
    }
  }

  return [...candidates.values()]
    .filter(({ cell, liveNeighbors }) => survives(liveCells.has(cellKey(cell)), liveNeighbors))
    .map(({ cell }) => cell);
};

